& { $ErrorActionPreference='Continue'; $root=(Resolve-Path -LiteralPath (Get-Location).Path).Path.TrimEnd('\','/'); $skip='[\\/](\.git|node_modules|dist|build|\.next|\.vite|coverage|tmp|temp|\.vercel|\.wrangler)[\\/]'; $assetExt=@('.png','.jpg','.jpeg','.webp','.gif','.svg','.avif','.mp4','.webm','.mov','.m4v','.mp3','.wav','.ogg','.glb','.gltf','.hdr','.ico','.woff','.woff2','.ttf','.otf','.pdf','.wasm'); $codeExt=@('.html','.css','.js','.mjs','.cjs','.jsx','.ts','.tsx','.json','.md'); $sb=[System.Text.StringBuilder]::new(); $all=Get-ChildItem -LiteralPath $root -Recurse -File -Force | Where-Object { $_.FullName -notmatch $skip } | Sort-Object FullName; $assets=$all | Where-Object { $assetExt -contains $_.Extension.ToLowerInvariant() }; $code=$all | Where-Object { $codeExt -contains $_.Extension.ToLowerInvariant() }; $refs=New-Object System.Collections.Generic.List[object]; $rx='(?i)(?<ref>[A-Za-z0-9_./\\:@%+\-]+?\.(png|jpe?g|webp|gif|svg|avif|mp4|webm|mov|m4v|mp3|wav|ogg|glb|gltf|hdr|ico|woff2?|ttf|otf|pdf|wasm)([?#][^"''\s)]*)?)'; foreach($f in $code){ $rel=$f.FullName.Substring($root.Length).TrimStart('\','/'); try { $lines=[System.IO.File]::ReadAllText($f.FullName,[System.Text.UTF8Encoding]::new($false)) -split "`r?`n" } catch { $lines=@() }; for($i=0;$i -lt $lines.Count;$i++){ $line=[string]$lines[$i]; foreach($m in [regex]::Matches($line,$rx)){ [void]$refs.Add([pscustomobject]@{Raw=$m.Groups['ref'].Value;File=$rel;Line=($i+1);Text=$line.Trim()}) } } }; [void]$sb.AppendLine('ASSET AUDIT'); [void]$sb.AppendLine('ROOT: ' + $root); [void]$sb.AppendLine('ASSETS: ' + $assets.Count); foreach($a in $assets){ $rel=$a.FullName.Substring($root.Length).TrimStart('\','/'); [void]$sb.AppendLine($rel + ' | ' + $a.Extension.ToLowerInvariant() + ' | ' + [Math]::Round($a.Length/1KB,2) + ' KB') }; [void]$sb.AppendLine(''); [void]$sb.AppendLine('REFERENCES'); foreach($r in $refs){ [void]$sb.AppendLine($r.File + ':' + $r.Line + ' | ' + $r.Raw + ' | ' + $r.Text) }; $result=$sb.ToString(); try { Set-Clipboard -Value $result } catch {}; Write-Host ('copied chars: ' + $result.Length); Write-Host ('assets indexed: ' + $assets.Count); Write-Host ('raw asset refs found: ' + $refs.Count) }
